    public Object parseMarket(Object market)
    {
        Object id = this.safeString(market, "name");
        Object numericId = this.safeInteger(market, "id");
        Object parts = Helpers.split(((String)id), "_");
        Object baseId = this.safeString(parts, 0);
        Object quoteId = this.safeString(parts, 1);
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object active = this.safeValue(market, "active");
        Object timeStart = this.safeString(market, "timeStart");
        Object created = this.parse8601(timeStart);
        Object minCost = null;
        Object currenciesValuedInUsd = this.handleOption("fetchMarkets", "currenciesValuedInUsd", new java.util.HashMap<String, Object>() {{}});
        Object quoteInUsd = this.safeBool(currenciesValuedInUsd, quote, false);
        if (Helpers.isTrue(quoteInUsd))
        {
            Object settings = this.safeValue(market, "settings", new java.util.HashMap<String, Object>() {{}});
            minCost = this.safeNumber(settings, "limit_usd");
        }
        final Object finalBase = base;
        final Object finalMinCost = minCost;
        return this.safeMarketStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "numericId", numericId );
            put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", false );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "active", active );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", BitteamCore.this.parseNumber(BitteamCore.this.parsePrecision(BitteamCore.this.safeString(market, "baseStep"))) );
                put( "price", BitteamCore.this.parseNumber(BitteamCore.this.parsePrecision(BitteamCore.this.safeString(market, "quoteStep"))) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", finalMinCost );
                    put( "max", null );
                }} );
            }} );
            put( "created", created );
            put( "info", market );
        }});
    }

