    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pairId", BitteamCore.this.safeString(market, "numericId") );
                put( "type", finalType );
                put( "side", side );
                put( "amount", BitteamCore.this.amountToPrecision(symbol, amount) );
            }};
            if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
            {
                if (Helpers.isTrue(Helpers.isEqual(price, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a price argument for a "), type), " order")) ;
                } else
                {
                    Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                }
            }
            Object response = (this.privatePostTradeApiCcxtOrdercreate(this.extend(request, parameters))).join();
            //
            //     {
            //         "ok": true,
            //         "result": {
            //             "id": 106733308,
            //             "userId": 21639,
            //             "quantity": "0.00001",
            //             "pair": "btc_usdt",
            //             "side": "buy",
            //             "price": "50000",
            //             "executed": "0",
            //             "executedPrice": "0",
            //             "status": "created",
            //             "baseDecimals": 8,
            //             "quoteDecimals": 6,
            //             "pairId": 22,
            //             "type": "limit",
            //             "stopPrice": null,
            //             "slippage": null,
            //             "timestamp": "1700594959"
            //         }
            //     }
            //
            Object order = this.safeDict(response, "result", new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(order, market);
        });

    }

