    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // fetchOrders
        //     {
        //         "id": 106733308,
        //         "orderId": "13074362",
        //         "userId": 21639,
        //         "pair": "btc_usdt",
        //         "pairId": 22,
        //         "quantity": "0.00001",
        //         "price": "50000",
        //         "executedPrice": "37017.495008",
        //         "fee": {
        //             "amount": "0.00000002",
        //             "symbol": "btc",
        //             "userId": 21639,
        //             "decimals": 8,
        //             "symbolId": 11
        //         },
        //         "orderCid": null,
        //         "executed": "0.00001",
        //         "expires": null,
        //         "baseDecimals": 8,
        //         "quoteDecimals": 6,
        //         "timestamp": 1700594959,
        //         "status": "executed",
        //         "side": "buy",
        //         "type": "limit",
        //         "createdAt": "2023-11-21T19:29:19.946Z",
        //         "updatedAt": "2023-11-21T19:29:19.946Z"
        //     },
        //
        // fetchOrder
        //     {
        //         "id": 106494347,
        //         "orderId": "13214332",
        //         "userId": 15912,
        //         "pair": "eth_usdt",
        //         "pairId": 2,
        //         "quantity": "0.00448598",
        //         "price": "2015.644995",
        //         "executedPrice": "2015.644995",
        //         "fee": {
        //             "amount": "0",
        //             "symbol": "eth",
        //             "userId": 15912,
        //             "decimals": 18,
        //             "symbolId": 2,
        //             "discountAmount": "0",
        //             "discountSymbol": "btt",
        //             "discountDecimals": 18,
        //             "discountSymbolId": 5
        //         },
        //         "orderCid": null,
        //         "executed": "0.00448598",
        //         "expires": null,
        //         "baseDecimals": 18,
        //         "quoteDecimals": 6,
        //         "timestamp": 1700470476,
        //         "status": "executed",
        //         "side": "buy",
        //         "type": "limit",
        //         "stopPrice": null,
        //         "slippage": null
        //     }
        //
        // createOrder
        //     {
        //         "id": 106733308,
        //         "userId": 21639,
        //         "quantity": "0.00001",
        //         "pair": "btc_usdt",
        //         "side": "buy",
        //         "price": "50000",
        //         "executed": "0",
        //         "executedPrice": "0",
        //         "status": "created",
        //         "baseDecimals": 8,
        //         "quoteDecimals": 6,
        //         "pairId": 22,
        //         "type": "limit",
        //         "stopPrice": null,
        //         "slippage": null,
        //         "timestamp": "1700594959"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "id");
        Object marketId = this.safeString(order, "pair");
        market = this.safeMarket(marketId, market);
        Object clientOrderId = this.safeString(order, "orderCid");
        Object timestamp = null;
        Object createdAt = this.safeString(order, "createdAt");
        if (Helpers.isTrue(!Helpers.isEqual(createdAt, null)))
        {
            timestamp = this.parse8601(createdAt);
        } else
        {
            timestamp = this.safeTimestamp(order, "timestamp");
        }
        Object updatedAt = this.safeString(order, "updatedAt");
        Object lastUpdateTimestamp = this.parse8601(updatedAt);
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object type = this.parseOrderType(this.safeString(order, "type"));
        Object side = this.safeString(order, "side");
        Object feeRaw = this.safeValue(order, "fee");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "quantity");
        Object filled = this.safeString(order, "executed");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeRaw, null)))
        {
            Object feeCost = this.safeString(feeRaw, "amount");
            Object feeCurrencyId = this.safeString(feeRaw, "symbol");
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", BitteamCore.this.safeCurrencyCode(feeCurrencyId) );
                put( "cost", feeCost );
                put( "rate", null );
            }};
        }
        final Object finalTimestamp = timestamp;
        final Object finalMarket = market;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", finalTimestamp );
            put( "datetime", BitteamCore.this.iso8601(finalTimestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", lastUpdateTimestamp );
            put( "status", status );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", type );
            put( "timeInForce", "GTC" );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", BitteamCore.this.safeString(order, "stopPrice") );
            put( "average", null );
            put( "amount", amount );
            put( "cost", null );
            put( "filled", filled );
            put( "remaining", null );
            put( "fee", finalFee );
            put( "trades", null );
            put( "info", order );
            put( "postOnly", false );
        }}, market);
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "accepted", "open" );
            put( "executed", "closed" );
            put( "cancelled", "canceled" );
            put( "partiallyCancelled", "canceled" );
            put( "delete", "rejected" );
            put( "inactive", "rejected" );
            put( "executing", "open" );
            put( "created", "open" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    public Object parseOrderType(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "market", "market" );
            put( "limit", "limit" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseValueToPricision(Object valueObject, Object valueKey, Object preciseObject, Object precisionKey)
    {
        Object valueRawString = this.safeString(valueObject, valueKey);
        Object precisionRawString = this.safeString(preciseObject, precisionKey);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(valueRawString, null)) || Helpers.isTrue(Helpers.isEqual(precisionRawString, null))))
        {
            return null;
        }
        Object precisionString = this.parsePrecision(precisionRawString);
        return Precise.stringMul(valueRawString, precisionString);
    }

