    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "trade_id": 34970337,
        //         "price": 37769.994793,
        //         "base_volume": 0.00119062,
        //         "quote_volume": 44.96971120044166,
        //         "timestamp": 1700827234000,
        //         "type": "buy"
        //     },
        //
        // fetchMyTrades
        //     {
        //         "id": 34875793,
        //         "tradeId": "4368010",
        //         "makerOrderId": 106742914,
        //         "takerOrderId": 106745926,
        //         "pairId": 2,
        //         "quantity": "0.0027193",
        //         "price": "1993.674994",
        //         "isBuyerMaker": true,
        //         "baseDecimals": 18,
        //         "quoteDecimals": 6,
        //         "side": "sell",
        //         "timestamp": 1700602983,
        //         "rewarded": true,
        //         "makerUserId": 21639,
        //         "takerUserId": 15912,
        //         "baseCurrencyId": 2,
        //         "quoteCurrencyId": 3,
        //         "feeMaker": {
        //             "amount": "0.00000543",
        //             "symbol": "eth",
        //             "userId": 21639,
        //             "decimals": 18,
        //             "symbolId": 2
        //         },
        //         "feeTaker": {
        //             "amount": "0",
        //             "symbol": "usdt",
        //             "userId": 15912,
        //             "decimals": 6,
        //             "symbolId": 3,
        //             "discountAmount": "0",
        //             "discountSymbol": "btt",
        //             "discountDecimals": 18,
        //             "discountSymbolId": 5
        //         },
        //         "pair": "eth_usdt",
        //         "createdAt": "2023-11-21T21:43:02.758Z",
        //         "updatedAt": "2023-11-21T21:45:00.147Z",
        //         "isCurrentSide": "maker"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "pair");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object id = this.safeString2(trade, "id", "trade_id");
        Object price = this.safeString(trade, "price");
        Object amount = this.safeString2(trade, "quantity", "base_volume");
        Object cost = this.safeString(trade, "quote_volume");
        Object takerOrMaker = this.safeString(trade, "isCurrentSide");
        Object timestamp = this.safeString(trade, "timestamp");
        if (Helpers.isTrue(!Helpers.isEqual(takerOrMaker, null)))
        {
            timestamp = Precise.stringMul(timestamp, "1000");
        }
        // the exchange returns the side of the taker
        Object side = this.safeString2(trade, "side", "type");
        Object feeInfo = null;
        Object order = null;
        if (Helpers.isTrue(Helpers.isEqual(takerOrMaker, "maker")))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, "sell")))
            {
                side = "buy";
            } else if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
            {
                side = "sell";
            }
            order = this.safeString(trade, "makerOrderId");
            feeInfo = this.safeValue(trade, "feeMaker", new java.util.HashMap<String, Object>() {{}});
        } else if (Helpers.isTrue(Helpers.isEqual(takerOrMaker, "taker")))
        {
            order = this.safeString(trade, "takerOrderId");
            feeInfo = this.safeValue(trade, "feeTaker", new java.util.HashMap<String, Object>() {{}});
        }
        Object feeCurrencyId = this.safeString(feeInfo, "symbol");
        Object feeCost = this.safeString(feeInfo, "amount");
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "currency", BitteamCore.this.safeCurrencyCode(feeCurrencyId) );
            put( "cost", feeCost );
        }};
        Object intTs = this.parseToInt(timestamp);
        final Object finalOrder = order;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", finalOrder );
            put( "timestamp", intTs );
            put( "datetime", BitteamCore.this.iso8601(intTs) );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", cost );
            put( "fee", fee );
            put( "info", trade );
        }}, market);
    }

