    public Object parseBalance(Object response)
    {
        //
        //     {
        //         "ok": true,
        //         "result": {
        //             "free": {
        //                 "USDT": "0",
        //                 "DEL": "0",
        //                 "BTC": "0",
        //                 ...
        //             },
        //                 "used": {
        //                 "USDT": "0",
        //                 "DEL": "0",
        //                 "BTC": "0",
        //                 ...
        //             },
        //             "total": {
        //                 "USDT": "0",
        //                 "DEL": "0",
        //                 "BTC": "0",
        //                 ...
        //             },
        //             "USDT": {
        //                 "free": "0",
        //                 "used": "0",
        //                 "total": "0",
        //             },
        //             "DEL": {
        //                 "free": "0",
        //                 "used": "0",
        //                 "total": "0",
        //             },
        //             "BTC": {
        //                 "free": "0",
        //                 "used": "0",
        //                 "total": "0",
        //             }
        //             ...
        //         }
        //     }
        //
        Object timestamp = this.milliseconds();
        Object balance = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", timestamp );
            put( "datetime", BitteamCore.this.iso8601(timestamp) );
        }};
        Object result = this.safeValue(response, "result", new java.util.HashMap<String, Object>() {{}});
        Object balanceByCurrencies = this.omit(result, new java.util.ArrayList<Object>(java.util.Arrays.asList("free", "used", "total")));
        Object rawCurrencyIds = Helpers.objectKeys(balanceByCurrencies);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawCurrencyIds)); i++)
        {
            Object rawCurrencyId = Helpers.GetValue(rawCurrencyIds, i);
            Object currencyBalance = this.safeValue(result, rawCurrencyId);
            Object free = this.safeString(currencyBalance, "free");
            Object used = this.safeString(currencyBalance, "used");
            Object total = this.safeString(currencyBalance, "total");
            Object currencyCode = this.safeCurrencyCode(((String)rawCurrencyId).toLowerCase());
            Helpers.addElementToObject(balance, currencyCode, new java.util.HashMap<String, Object>() {{
    put( "free", free );
    put( "used", used );
    put( "total", total );
}});
        }
        return this.safeBalance(balance);
    }

